-- ============================================================================
-- VERIFICATION
-- ============================================================================

-- Check the counts
SELECT 'Nodes inserted:' as check_type, COUNT(*) as count FROM nodes
UNION ALL
SELECT 'Links inserted:', COUNT(*) FROM links
UNION ALL
SELECT 'Invites created:', COUNT(*) FROM node_invites;

-- Show the test invite
SELECT 
  'Test Invite URL' as info,
  'http://localhost:5173/invite/' || token as url,
  'Expires: ' || expires_at::text as expiry
FROM node_invites
WHERE token = 'test-invite-fahd-2026';
